TOOL_CATALOG = [
    {
        "name": "web_search",
        "description": "Search the web for current information.",
        "parameters": {
            "query": "string — the search query",
        },
    },
    {
        "name": "run_code",
        "description": "Execute Python code in a sandbox and return stdout.",
        "parameters": {
            "code": "string — valid Python code",
        },
    },
    {
        "name": "read_file",
        "description": "Read a file from the workspace.",
        "parameters": {
            "path": "string — file path relative to workspace root",
        },
    },
    {
        "name": "write_file",
        "description": "Write content to a file in the workspace.",
        "parameters": {
            "path": "string — destination path",
            "content": "string — file content",
        },
    },
]

def format_tool_catalog(tools: list[dict]) -> str:
    lines = []
    for tool in tools:
        params = ", ".join(f"{k}: {v}" for k, v in tool["parameters"].items())
        lines.append(f"- {tool['name']}({params}): {tool['description']}")
    return "\n".join(lines)

LLM_PLANNER_PROMPT = """
You are an LLM acting as a planner. Your role is to reason about a goal
and produce an ordered list of tool calls that, when executed, achieves it.

Available tools:
{tool_catalog}

Context from prior work:
{memory}

Goal: {goal}

Think step-by-step:
1. What information do I need that I don't already have?
2. What computations or transformations are needed?
3. What outputs does the user expect?
4. What is the most efficient order of operations?

Return JSON:
{{
  "reasoning": "<brief chain-of-thought>",
  "steps": [
    {{"index": 1, "tool": "<name>", "args": {{...}},
      "rationale": "<why this step>", "depends_on": []}},
    ...
  ],
  "risks": ["<potential failure>", ...]
}}
"""

def llm_planner(goal: str, memory: str = "") -> dict:
    catalog_text = format_tool_catalog(TOOL_CATALOG)
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=2048,
        messages=[{"role": "user", "content": LLM_PLANNER_PROMPT.format(
            tool_catalog=catalog_text,
            memory=memory or "None.",
            goal=goal,
        )}],
    )
    return json.loads(response.content[0].text)

def llm_planner_with_tool_use(goal: str, memory: str = "") -> dict:
    """LLM planner that uses Anthropic tool_use API for structured output.

    This eliminates JSON parsing errors entirely by having the model
    call an 'emit_plan' tool with a validated schema.
    """
    PLAN_SCHEMA = {
        "type": "object",
        "properties": {
            "reasoning": {"type": "string"},
            "steps": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["index", "tool", "args", "rationale", "depends_on"],
                    "properties": {
                        "index":      {"type": "integer"},
                        "tool":       {"type": "string",
                                       "enum": [t["name"] for t in TOOL_CATALOG]},
                        "args":       {"type": "object"},
                        "rationale":  {"type": "string"},
                        "depends_on": {"type": "array", "items": {"type": "integer"}},
                    },
                },
            },
            "risks": {"type": "array", "items": {"type": "string"}},
        },
        "required": ["reasoning", "steps", "risks"],
    }
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=2048,
        tools=[{"name": "emit_plan", "description": "Output the plan.",
                "input_schema": PLAN_SCHEMA}],
        tool_choice={"type": "any"},
        messages=[{"role": "user", "content": LLM_PLANNER_PROMPT.format(
            tool_catalog=format_tool_catalog(TOOL_CATALOG),
            memory=memory or "None.",
            goal=goal,
        )}],
    )
    tool_use_block = next(b for b in response.content if b.type == "tool_use")
    return tool_use_block.input

# Planner Evaluation: measure plan quality on a held-out task set

EVAL_TASKS = [
    {
        "goal": "Search for the top 3 Python web frameworks and compare them",
        "expected_tools": ["web_search", "write_file"],
        "min_steps": 2, "max_steps": 5,
    },
    {
        "goal": "Read requirements.txt and generate a summary report",
        "expected_tools": ["read_file", "write_file"],
        "min_steps": 2, "max_steps": 3,
    },
]

def evaluate_planner(tasks: list[dict]) -> dict:
    results = []
    for task in tasks:
        plan = llm_planner(task["goal"])
        used_tools = {s["tool"] for s in plan["steps"]}
        expected   = set(task["expected_tools"])
        n_steps    = len(plan["steps"])
        results.append({
            "goal":          task["goal"],
            "tool_recall":   len(used_tools & expected) / len(expected),
            "tool_precision":len(used_tools & expected) / max(len(used_tools), 1),
            "step_ok":       task["min_steps"] <= n_steps <= task["max_steps"],
            "n_steps":       n_steps,
        })
    avg_recall    = sum(r["tool_recall"] for r in results) / len(results)
    avg_precision = sum(r["tool_precision"] for r in results) / len(results)
    step_ok_pct   = sum(r["step_ok"] for r in results) / len(results)
    return {
        "details":       results,
        "avg_recall":    round(avg_recall, 2),
        "avg_precision": round(avg_precision, 2),
        "step_ok_pct":   round(step_ok_pct, 2),
    }
